var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"학……! 하악……! 하아……!","JPN":"はっ……！　はあっ……！　はあ……！","ENG":"Haa....! Haah...! Haaah...!","TWN":"呼……！呼呼……！呼呼……！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"따돌렸나? 한창 싸우고 있었으니까 여기까지는 못 쫓아오겠지?","JPN":"うまく撒いた？　戦ってる最中だったからここまでは追ってこられないよね？","ENG":"Did I lose them? They were in the middle of fighting, so they couldn’t have chased me all this way, right?","TWN":"甩掉他們了嗎？打得那麼激烈，應該不會追到這裡來吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"꺄악?!","JPN":"きゃっ！？","ENG":"Kyaak?!","TWN":"唔？！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":"잡았습니다, 사제님.","JPN":"捕らえました、司祭様。","ENG":"We have captured her, Your Grace.","TWN":"抓到人了，祭司大人。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L12_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"좋아요. 발악하지 못하게 결박해 두세요.","JPN":"結構です。暴れないように縛っておきなさい。","ENG":"Good work. Tie her up so that she can’t run away.","TWN":"很好，把人綁起來，別讓她逃了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"그, 그 애한테 정신 팔려 있던 거 아니었어?! 어떻게 여기까지……?!","JPN":"あ、あの子に気を取られていたんじゃなかったの！？　どうやってここまで……！？","ENG":"W-weren’t you busy with the other guy?! How did you track me to here...?!","TWN":"你…你們不是忙著對付他嗎？！怎麼會追到這裡來……？！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"지팡이를 받을 때 만약을 대비해 당신에게 추적 마법을 걸어 뒀어요.","JPN":"杖を受け取るとき、もしもの際に備えてあなたに追跡魔法をかけておきました。","ENG":"When I received the staff, I placed a tracking spell on you just in case.","TWN":"以防萬一，在我拿到杖時，就對你下了追蹤魔法。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"하지만 설마 자기 편을 버리고 도망치다니…… 과연 천한 노예로군요.","JPN":"でもまさか味方を見捨てて逃げるなんて……さすがは卑しい奴隷ですね。","ENG":"But I never expected you to abandon your ally and run... You really are a lowly slave.","TWN":"不過我沒想到你會扔下夥伴逃跑……果然是卑賤的奴隸。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"죽기 전에 사과할 기회는 드리죠. 다른 기사들이 그 소년도 곧 데리고 올 겁니다.","JPN":"死ぬ前に謝る機会を与えてあげましょう。他の騎士がすぐあの少年も連れてくるでしょう。","ENG":"I will give you a chance to apologize to him before you die. The other knights will be bringing the boy here soon.","TWN":"我給你個在死前道歉的機會吧，其他騎士很快就會把他帶過來。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"……누가 사과 따위를 한다고 그래?","JPN":"……誰が謝るって言うの？","ENG":"...Who said that I will be apologizing?","TWN":"……誰要跟他道歉？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"멍청하게 은전 몇 푼 받을지도 모른다는 말에 혹해서 따라온 게 잘못 아냐?","JPN":"バカみたく小銭に惑わされてついてきた人が悪いんでしょ？","ENG":"Isn’t it his fault for stupidly following me over the promise of a few coins?","TWN":"要怪就怪他自己財迷心竅，說要賞他一點銀子，就傻傻地跟到這裡來！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"어차피 세상에 믿을 사람은 아무도 없어. 나 자신 말고는.","JPN":"どうせこの世界に信じられる人は誰もいない。自分以外には。","ENG":"After all, you can’t trust anybody in this world. Only yourself.","TWN":"在這個世界上沒有一個人是可以相信的！除了自己以外！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"호오. 천한 노예 주제에 세상의 진실을 알고 있구나.","JPN":"ほお。卑しい奴隷の分際で世界の真実を知っているとはね。","ENG":"Oh? For a lowly slave, you understand the truth about this world.","TWN":"呵呵，不過是一個卑賤的奴隸，倒是看得很透澈嘛。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"이 목소리는…… 남쪽 신전의 신전장?","JPN":"この声は……南方の神殿の神殿長？","ENG":"This voice... Head Priestess of the Southern Temple?","TWN":"這個聲音是……南方神殿的祭司長？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"같은 성녀 후보로서 통탄할 노릇이야.","JPN":"同じ聖女候補として嘆かわしいことね。","ENG":"As a fellow candidate for the Sainthood, what a deplorable sight this is.","TWN":"同樣身為聖女候選人，我都替你感到難過。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"이런 더러운 곳에서 노예 계집애와 실랑이나 벌이고 있다니.","JPN":"こんなうす汚いところで奴隷の小娘とケンカしてるなんて。","ENG":"Quarrelling with a slave girl in such a disgusting place.","TWN":"竟然在如此骯髒的地方和奴隸在那瞎折騰。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"야, 이 겁쟁아! 바보 같이 붙잡힌 거야?","JPN":"この弱虫！　バカみたいに捕まちゃったの？","ENG":"Hey, you coward! Were you also caught like an idiot again?","TWN":"喂，膽小鬼！你就這樣傻傻地被抓起來嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"미, 미안. 저항하면 널 아주 고통스럽게 만들 거라고 했거든.","JPN":"ご、ごめん。抵抗すると君をめちゃくちゃ苦しめるって言うから。","ENG":"S-sorry. They threatened to torture you if I resisted.","TWN":"對…對不起，我怕我抵抗的話，他們會傷害你。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"어디서 그 소년을 찾은 거죠? 남아 있던 기사들은요?","JPN":"どこでその少年を見つけたのですか？　残っていた騎士たちは？","ENG":"Where did you find that boy? What happened to the remaining knights?","TWN":"你是在哪裡找到那個少年的？其他的騎士呢？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"그 자들이라면 신경 쓸 필요 없다. 내 수행원들이 깨끗이 치워 버렸으니 말이야.","JPN":"あの者たちなら気にする必要はないわ。私の御供がキレイに片付けたからね。","ENG":"If it’s the knights you are concerned for, there’s no need to be so. My entourage has taken care of them.","TWN":"你不必擔心他們，我的隨從把他們都處理乾淨了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"어떻게……! 처음부터 알고 있었단 건가요?","JPN":"どうやって……！　最初から知っていたのですか？","ENG":"How...?! You knew about my plans from the start?!","TWN":"怎麼會……！你打從一開始就知情嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"설마 그 하찮은 노예 계집이 제 힘만 가지고 부활의 지팡이를 훔칠 수 있을 거라 믿진 않았겠지?","JPN":"まさかあのつまらない奴隷の小娘が自分の力のみで復活の杖を盗めるとでも思ったの？","ENG":"Don’t tell me you actually thought that some lowly slave girl would be able to steal the Staff of Resurrection by herself?","TWN":"你不會真的相信，那個不起眼的小丫頭可以靠自己的力量偷走復活之杖吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"그래. 대신전의 경비가 소홀해지도록 손을 쓴 것이 바로 나다.","JPN":"そう。大神殿の警戒が手薄になるように手を打ったのはこの私よ。","ENG":"That’s right. I’m the one who ensured that the security at the Great Temple would be relaxed.","TWN":"沒錯，是我出手讓大神殿的戒備鬆懈下來的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"어째서 그런 거죠? 그 전에 대신전에 사실을 알리면 될 것을!","JPN":"どうしてそんなことを？　その前に大神殿に知らせればいいものを！","ENG":"Why would you do such a thing? You could’ve alerted the Great Temple beforehand!","TWN":"你為什麼要那麼做？你大可以直接向大神殿告發我！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"어리석구나. 모름지기 진정으로 고귀한 자는 자신의 손을 더럽히지 않는 법.","JPN":"愚かね。すべからく真に尊き者は自分の手を汚さないもの。","ENG":"How foolish. It’s common sense that a true noble will never get their own hands dirty.","TWN":"真是愚蠢，借刀殺人你沒聽過嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"네 검은 속셈을 알려 봐야 내게 무슨 이득이 있느냐? 그래서야 수지가 안 맞지.","JPN":"あなたの黒き下心を知らせて、私が何の得をするというの？　それでは釣り合わないわ。","ENG":"What do I gain from merely exposing your vile plan? Such a shallow move is below me.","TWN":"揭發你的陰謀對我有什麼好處？完全沒有。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"하지만 이렇게 도난 당한 지팡이를 회수해 간다면……","JPN":"でも、こうして盗まれた杖を回収していけば……","ENG":"However, if I recover the stolen staff like this...","TWN":"但若是我將被偷走的杖找回來……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"그 공으로 나는 정당하게 성녀가 될 수 있겠지.","JPN":"その手柄で私は正々堂々聖女になれるでしょう。","ENG":"I will be rightfully appointed as the Saintess for my feat.","TWN":"我就可以立下功勞，接著順理成章地當上聖女。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"후후, 정말 감사하고 싶을 정도야.","JPN":"ふふ、まったく感謝したいくらいよ。","ENG":"Fufu, I have so much to be thankful for to you.","TWN":"呵呵，這都得感謝你呢。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"이……! 이 비열한 자가……!","JPN":"この……！　この卑劣な……！","ENG":"You...! Vile person...!","TWN":"唔……！卑鄙的傢伙……！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L23_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"뭘 가만히 있나요! 어서 저 간사한 여자를 죽이세요!","JPN":"何をぼけっとしてるのです！　早くあのずる賢い女を殺しなさい！","ENG":"Why are you all just standing about? Quickly kill that crafty vixen!","TWN":"還楞著做什麼！快把那狡猾的女人給我殺了！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":"아, 알겠습니다! 사제님!","JPN":"わ、わかりました！　司祭様！","ENG":"Y-yes, Your Grace!","TWN":"呃，是，遵命！"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L26_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"마지막까지도 어리석구나. 방금 전에 내 수행원들에 대해서 말했을 텐데?","JPN":"最後まで愚かな。さっき私の御供について言ったはずだけど？","ENG":"Foolish until the end, I see. I’m pretty sure I mentioned my entourage just now.","TWN":"你真是愚蠢至極呢，我剛才應該有提到我的隨從吧？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"저, 저건…… 마왕이 부리는 괴물들이잖아?","JPN":"あ、あれは……魔王の化け物じゃない。","ENG":"W-what...? Those are monsters controlled by the Demon Lord!","TWN":"那不是……魔王操控的怪物嗎？"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"이, 이 비열하고 사악한 자가! 신전장이면서 마왕과 손을 잡다니!","JPN":"こ、この卑劣で邪悪な者め！　神殿長でありながら魔王と手を組むとは！","ENG":"Y-you evil, vile woman! How could you??! The Head Priestess joining forces with the Demon Lord?!","TWN":"你…你這卑鄙又邪惡的傢伙！身為祭司長竟然和魔王有勾結！"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"후후, 기억해 두도록 해라.","JPN":"ふふ、よく覚えておくといいわ。","ENG":"Fufu, here’s something you should remember.","TWN":"呵呵，你千萬要記住，"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"이런 불확실한 시대에는 하나의 줄만 쥐고 있어서는 안 된다는 것을.","JPN":"このような不確実な時代には、保身のための関係は一つでは足りないということを。","ENG":"In such uneasy times like these, you shouldn’t put all of your eggs in one basket.","TWN":"在這動盪不安的時代，絕對不能把雞蛋放在同一個籃子裡。"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"뭐, 너희들에게는 너무 늦은 충고겠지만.","JPN":"ま、あなたたちには遅すぎた忠告だろうけど。","ENG":"Well, I guess it’s already too late for you...","TWN":"不過現在跟你們說這些也沒用了。"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"부활의 지팡이를 훔친 중죄인들은 일단 살려둬라.","JPN":"復活の杖を盗んだ重罪人はとりあえず生かしておきなさい。","ENG":"Spare the criminals who stole the Staff of Resurrection for now.","TWN":"竊取復活之杖的罪人就暫且留他們活口，"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"그 녀석들에게는 화려한 정식 화형대가 필요하니까.","JPN":"あいつらには派手な正式の火刑台が必要だからね。","ENG":"After all, they deserve to be burned at the stake in an extravagant public execution.","TWN":"他們必須接受華麗的火刑。"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"나머지 서쪽 신전의 찌꺼기들은…… 모조리 먹어 치워라.","JPN":"西方の神殿の残りかすは……すべて食いつくしておしまい。","ENG":"As for the remaining Western Temple scum... Devour them to the last bone.","TWN":"西方神殿的其餘人等……一個不留！"},"stage":{"bg":"UNDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}}]`);export{e as default};